local HyperlinkJumpType = HyperlinkJumpType

local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxChatCtrl:LxBaseCtrl
local LxChatCtrl = classX("LxChatCtrl", LxBaseCtrl)

function LxChatCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxChatCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

function LxChatCtrl:InitAfterLoginGame()
    self:InitAfterLoginGameEvents()
    self._isInitAfterLoginGame = true
end

function LxChatCtrl:InitAfterLoginGameEvents()
    if self._isInitAfterLoginGame then return end
    self:AddEventHandler(EventNames.ROLE_ONLINE_STATE, self.OnRoleOnlineState, self)
end

-- 私聊
function LxChatCtrl:OnChatPrivate(param)
    param = param or {}
    local panelMgr = MgrCenter.PanelMgr
    local ctrl = panelMgr:GetPanelCtrl(UiNames.Chat)
    if not ctrl then
        ctrl = panelMgr:ShowPanel(UiNames.Chat)
    end

    if param.roleInfo then
        ModuleCenter.Chat:AddPrivateRole(param.roleInfo)
    end

    ctrl:SetParamData({ chatCtrlType = ChatCtrlType.Chat, channel = ChatChannel.Private, privateRoleInfo = param.roleInfo })
    if ctrl:IsPanelReady() then
        ctrl:OnChatPrivate()
    end

    local change, list = ModuleCenter.Chat:GetPrivateRoleIdList()
    if change then
        HandlerCenter.Common:CheckOfflineTimeReq(list)
    end
end

-- 查看玩家
function LxChatCtrl:OnChatLookAtPlayer(param)
    param = param or {}
    if not param.roleId then
        return
    end
    if ModuleCenter.Login:IsSelf(param.roleId) then
        ShowSysMsg(I18nText(6539))
        return
    end

    --HandlerCenter.Role:RoleInfoShowReq(param.roleId)
    ShowPanel(UiNames.RoleInfo, { roleId = param.roleId, msg = param.msg })
end

-- 点击聊天超链接
function LxChatCtrl:OnClickChatlink(params, strMsg, chatObj)
    if (params.type == HyperlinkType.Web) then
        UnityEngine.Application.OpenURL(params.data)
        return
    end

    if params.type ~= HyperlinkType.Data then
        return
    end

    local key = params.key or ""
    local data = params.data or ""
    if key == HyperlinkJumpType.JumpFunc then
        local funcId = checknumber(data)

        if funcId == 0 then
            printInfo2("功能调转id为空:", strMsg)
            return
        end
        printInfo2(funcId, FuncOpnIdConst.Bag, FuncOpnIdConst.Bag == funcId)
        CtrlCenter.FuncOpen:JumpTo(funcId)
        return
    end

    if key == HyperlinkJumpType.PlayInfo then
        local roleId = data
        if roleId == "" then
            printInfo2("玩家详情roleId为空:", strMsg)
            return
        end

        self:OnChatLookAtPlayer({ roleId = roleId })
        return
    end

    if key == HyperlinkJumpType.ItemInfo then
        local refId = checknumber(data)
        if refId == 0 then
            printInfo2("道具详情refId为空:", strMsg)
            return
        end
        FireEvent(EventNames.SHOW_TIPS, { type = ThingType.Item, refId = refId, share = true, from = UiNames.Chat })
        return
    end

    if key == HyperlinkJumpType.HeroInfo then
        local refId = checknumber(data)
        if refId == 0 then
            printInfo2("英雄详情refId为空:", strMsg)
            return
        end
        FireEvent(EventNames.SHOW_TIPS, { type = ThingType.Hero, refId = refId, from = UiNames.Chat })
    end

    if key == HyperlinkJumpType.GuildInfo then
        local guildId = data
        if guildId == "" then
            printInfo2("军团详情guildId为空:", strMsg)
            return
        end

        CtrlCenter.Guild:ShowGuildInfo(guildId)
        return
    end

    if key == HyperlinkJumpType.GuildDetails then
        local guildId = data
        if guildId == "" then
            printInfo2("军团详情guildId为空:", strMsg)
            return
        end

        CtrlCenter.Guild:ShowGuildInfo(guildId)
        return
    end

    if key == HyperlinkJumpType.AssistInfo then
        local gridInfo = data
        if gridInfo == "" then
            printInfo2("援軍位置gridInfo为空:", strMsg)
            return
        end
        local sMsgList = string.split(gridInfo, ",")
        local posX = checknumber(sMsgList[1])   -- 坐标信息
        local posZ = checknumber(sMsgList[2])   -- 坐标信息
        CtrlCenter.World:GoWorld({gridX = posX, gridZ = posZ, time = 1})
        return
    end
    printInfo2("未处理点击聊天超链接：key=" .. key .. " data=" .. data)
end

-- 角色在线状态
function LxChatCtrl:OnRoleOnlineState(roleMap)
    for roleId, info in pairs(roleMap) do
        ModuleCenter.Chat:SetPrivateRoleInfo(roleId, info)
    end
    FireEvent(EventNames.CHAT_PRIVATE_ONLINE_CHANGE)
end

function LxChatCtrl:OnDelPrivateRoleChat(roleId)
    ModuleCenter.Chat:DelPrivateRoleChat(roleId)
    FireEvent(EventNames.CHAT_DEL_PRIVATEIFNO)
end

return LxChatCtrl
